@Repository
class ProductSearchRepository {

    private static final String PRODUCT_INDEX = "products";
    private static final String QUERY_LOG_INDEX = "search_queries";

    private final RestHighLevelClient client;

    public ProductSearchRepository(RestHighLevelClient client) {
        this.client = client;
    }

    @PostConstruct
    public void init() {
        try {
            ensureIndices();
        } catch (IOException e) {
            throw new RuntimeException(e);
        }
    }

    private void ensureIndices() throws IOException {
        GetIndexRequest productIndexExists = new GetIndexRequest(PRODUCT_INDEX);
        if (!client.indices().exists(productIndexExists, RequestOptions.DEFAULT)) {
            CreateIndexRequest createIndexRequest = new CreateIndexRequest(PRODUCT_INDEX);
            createIndexRequest.settings(Settings.builder()
                    .put("index.number_of_shards", 1)
                    .put("index.number_of_replicas", 0));

            XContentBuilder mapping = XContentFactory.jsonBuilder();
            mapping.startObject();
            mapping.startObject("properties");

            mapping.startObject("id").field("type", "keyword").endObject();
            mapping.startObject("name").field("type", "text")
                    .startObject("fields").startObject("keyword").field("type", "keyword").field("ignore_above", 256).endObject().endObject()
                    .endObject();
            mapping.startObject("description").field("type", "text").endObject();
            mapping.startObject("brand").field("type", "keyword").endObject();
            mapping.startObject("category").field("type", "keyword").endObject();
            mapping.startObject("tags").field("type", "keyword").endObject();
            mapping.startObject("price").field("type", "double").endObject();
            mapping.startObject("currency").field("type", "keyword").endObject();
            mapping.startObject("inStock").field("type", "boolean").endObject();
            mapping.startObject("rating").field("type", "integer").endObject();
            mapping.startObject("attributes").field("type", "object").endObject();
            mapping.startObject("createdAt").field("type", "date").endObject();
            mapping.startObject("updatedAt").field("type", "date").endObject();

            mapping.endObject();
            mapping.endObject();
            createIndexRequest.mapping(mapping);
            client.indices().create(createIndexRequest, RequestOptions.DEFAULT);
        }

        GetIndexRequest queryIndexExists = new GetIndexRequest(QUERY_LOG_INDEX);
        if (!client.indices().exists(queryIndexExists, RequestOptions.DEFAULT)) {
            CreateIndexRequest createIndexRequest = new CreateIndexRequest(QUERY_LOG_INDEX);
            createIndexRequest.settings(Settings.builder()
                    .put("index.number_of_shards", 1)
                    .put("index.number_of_replicas", 0));

            XContentBuilder mapping = XContentFactory.jsonBuilder();
            mapping.startObject();
            mapping.startObject("properties");
            mapping.startObject("id").field("type", "keyword").endObject();
            mapping.startObject("query").field("type", "text").endObject();
            mapping.startObject("userId").field("type", "keyword").endObject();
            mapping.startObject("sessionId").field("type", "keyword").endObject();
            mapping.startObject("timestamp").field("type", "date").endObject();
            mapping.startObject("resultCount").field("type", "integer").endObject();
            mapping.startObject("filters").field("type", "object").endObject();
            mapping.endObject();
            mapping.endObject();
            createIndexRequest.mapping(mapping);
            client.indices().create(createIndexRequest, RequestOptions.DEFAULT);
        }
    }

    public Product saveProduct(Product product) throws IOException {
        if (product.getId() == null || product.getId().isEmpty()) {
            product.setId(UUID.randomUUID().toString());
        }
        Instant now = Instant.now();
        if (product.getCreatedAt() == null) product.setCreatedAt(now);
        product.setUpdatedAt(now);

        IndexRequest request = new IndexRequest(PRODUCT_INDEX)
                .id(product.getId())
                .source(toMap(product))
                .setRefreshPolicy(WriteRequest.RefreshPolicy.IMMEDIATE);

        IndexResponse response = client.index(request, RequestOptions.DEFAULT);
        product.setId(response.getId());
        return product;
    }

    public void deleteProduct(String id) throws IOException {
        DeleteRequest request = new DeleteRequest(PRODUCT_INDEX, id).setRefreshPolicy(WriteRequest.RefreshPolicy.IMMEDIATE);
        DeleteResponse response = client.delete(request, RequestOptions.DEFAULT);
    }

    public SearchResult search(String q, Map<String, String> filters, int page, int size) throws IOException {
        SearchRequest request = new SearchRequest(PRODUCT_INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.from(page * size);
        sourceBuilder.size(size);

        BoolQueryBuilder bool = QueryBuilders.boolQuery();

        if (q != null && !q.isBlank()) {
            MultiMatchQueryBuilder fullText = QueryBuilders.multiMatchQuery(q, "name^4", "description^2", "brand^3", "category^2", "tags^2")
                    .fuzziness(Fuzziness.AUTO)
                    .operator(MultiMatchQueryBuilder.Operator.AND);
            bool.must(fullText);
        } else {
            bool.must(QueryBuilders.matchAllQuery());
        }

        if (filters != null) {
            if (filters.containsKey("brand")) {
                bool.filter(QueryBuilders.termQuery("brand", filters.get("brand")));
            }
            if (filters.containsKey("category")) {
                bool.filter(QueryBuilders.termQuery("category", filters.get("category")));
            }
            if (filters.containsKey("inStock")) {
                bool.filter(QueryBuilders.termQuery("inStock", Boolean.parseBoolean(filters.get("inStock"))));
            }
            if (filters.containsKey("currency")) {
                bool.filter(QueryBuilders.termQuery("currency", filters.get("currency")));
            }
            if (filters.containsKey("minPrice") || filters.containsKey("maxPrice")) {
                double min = filters.containsKey("minPrice") ? Double.parseDouble(filters.get("minPrice")) : Double.NEGATIVE_INFINITY;
                double max = filters.containsKey("maxPrice") ? Double.parseDouble(filters.get("maxPrice")) : Double.POSITIVE_INFINITY;
                bool.filter(QueryBuilders.rangeQuery("price").gte(min).lte(max));
            }
        }

        sourceBuilder.query(bool);
        sourceBuilder.sort("rating", SortOrder.DESC);
        sourceBuilder.sort("price", SortOrder.ASC);

        sourceBuilder.aggregation(AggregationBuilders.terms("brand_facet").field("brand").size(20));
        sourceBuilder.aggregation(AggregationBuilders.terms("category_facet").field("category").size(20));
        sourceBuilder.aggregation(AggregationBuilders.terms("currency_facet").field("currency").size(20));
        sourceBuilder.aggregation(AggregationBuilders.terms("inStock_facet").field("inStock").size(2));
        sourceBuilder.trackTotalHits(true);

        request.source(sourceBuilder);
        SearchResponse response = client.search(request, RequestOptions.DEFAULT);

        List<Product> products = Arrays.stream(response.getHits().getHits())
                .map(this::fromHit)
                .collect(Collectors.toList());

        Map<String, Map<String, Long>> facets = new HashMap<>();
        facets.put("brand", parseTermsFacet(response, "brand_facet"));
        facets.put("category", parseTermsFacet(response, "category_facet"));
        facets.put("currency", parseTermsFacet(response, "currency_facet"));
        facets.put("inStock", parseTermsFacet(response, "inStock_facet"));

        return new SearchResult(products, response.getHits().getTotalHits() != null ? response.getHits().getTotalHits().value : products.size(), facets);
    }

    public SearchQueryLog saveQueryLog(SearchQueryLog log) throws IOException {
        if (log.getId() == null || log.getId().isEmpty()) {
            log.setId(UUID.randomUUID().toString());
        }
        if (log.getTimestamp() == null) log.setTimestamp(Instant.now());

        IndexRequest request = new IndexRequest(QUERY_LOG_INDEX)
                .id(log.getId())
                .source(toMap(log))
                .setRefreshPolicy(WriteRequest.RefreshPolicy.IMMEDIATE);

        client.index(request, RequestOptions.DEFAULT);
        return log;
    }

    public List<String> suggestPopularQueries(String prefix, int size) throws IOException {
        SearchRequest request = new SearchRequest(QUERY_LOG_INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.size(0);
        sourceBuilder.query(QueryBuilders.prefixQuery("query", prefix == null ? "" : prefix.toLowerCase()));
        sourceBuilder.aggregation(AggregationBuilders.terms("popular_queries").field("query.keyword").size(size));
        request.source(sourceBuilder);

        SearchResponse response = client.search(request, RequestOptions.DEFAULT);
        ParsedStringTerms terms = response.getAggregations().get("popular_queries");
        if (terms == null) return Collections.emptyList();

        List<String> suggestions = new ArrayList<>();
        for (ParsedStringTerms.Bucket bucket : terms.getBuckets()) {
            suggestions.add(bucket.getKeyAsString());
        }
        return suggestions;
    }

    private Map<String, Object> toMap(Product p) {
        Map<String, Object> map = new HashMap<>();
        map.put("id", p.getId());
        map.put("name", p.getName());
        map.put("description", p.getDescription());
        map.put("brand", p.getBrand());
        map.put("category", p.getCategory());
        map.put("tags", p.getTags());
        map.put("price", p.getPrice());
        map.put("currency", p.getCurrency());
        map.put("inStock", p.getInStock());
        map.put("rating", p.getRating());
        map.put("attributes", p.getAttributes());
        map.put("createdAt", p.getCreatedAt() != null ? p.getCreatedAt().toString() : null);
        map.put("updatedAt", p.getUpdatedAt() != null ? p.getUpdatedAt().toString() : null);
        return map;
    }

    private Map<String, Object> toMap(SearchQueryLog l) {
        Map<String, Object> map = new HashMap<>();
        map.put("id", l.getId());
        map.put("query", l.getQuery());
        map.put("userId", l.getUserId());
        map.put("sessionId", l.getSessionId());
        map.put("timestamp", l.getTimestamp() != null ? l.getTimestamp().toString() : null);
        map.put("resultCount", l.getResultCount());
        map.put("filters", l.getFilters());
        return map;
    }

    private Product fromHit(SearchHit hit) {
        Map<String, Object> src = hit.getSourceAsMap();
        Product p = new Product();
        p.setId((String) src.get("id"));
        p.setName((String) src.get("name"));
        p.setDescription((String) src.get("description"));
        p.setBrand((String) src.get("brand"));
        p.setCategory((String) src.get("category"));
        Object tags = src.get("tags");
        if (tags instanceof List) p.setTags(((List<?>) tags).stream().map(Object::toString).toArray(String[]::new));
        p.setPrice(src.get("price") != null ? Double.valueOf(src.get("price").toString()) : null);
        p.setCurrency((String) src.get("currency"));
        p.setInStock(src.get("inStock") != null ? Boolean.valueOf(src.get("inStock").toString()) : null);
        p.setRating(src.get("rating") != null ? Integer.valueOf(src.get("rating").toString()) : null);
        Object attrs = src.get("attributes");
        if (attrs instanceof Map) p.setAttributes((Map<String, Object>) attrs);
        return p;
    }

    private Map<String, Long> parseTermsFacet(SearchResponse response, String aggName) {
        ParsedStringTerms terms = response.getAggregations().get(aggName);
        if (terms == null) return Collections.emptyMap();
        Map<String, Long> map = new LinkedHashMap<>();
        for (ParsedStringTerms.Bucket bucket : terms.getBuckets()) {
            map.put(bucket.getKeyAsString(), bucket.getDocCount());
        }
        return map;
    }
}

@Service
class ProductSearchService {

    private final ProductSearchRepository repository;

    public ProductSearchService(ProductSearchRepository repository) {
        this.repository = repository;
    }

    public Product indexProduct(Product product) throws IOException {
        return repository.saveProduct(product);
    }

    public void deleteProduct(String id) throws IOException {
        repository.deleteProduct(id);
    }

    public SearchResult searchProducts(String q, Map<String, String> filters, int page, int size, String userId, String sessionId) throws IOException {
        SearchResult result = repository.search(q, filters, page, size);
        SearchQueryLog log = new SearchQueryLog();
        log.setQuery(q);
        log.setUserId(userId);
        log.setSessionId(sessionId);
        log.setResultCount((int) result.getTotal());
        log.setFilters(new HashMap<>(filters == null ? Collections.emptyMap() : filters));
        repository.saveQueryLog(log);
        return result;
    }

    public List<String> suggestQueries(String prefix, int size) throws IOException {
        return repository.suggestPopularQueries(prefix, size);
    }
}

@RestController
@RequestMapping("/api/products")
class ProductController {

    private final ProductSearchService service;

    public ProductController(ProductSearchService service) {
        this.service = service;
    }

    @PostMapping
    public ResponseEntity<Product> index(@RequestBody Product product) throws IOException {
        return ResponseEntity.ok(service.indexProduct(product));
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> delete(@PathVariable String id) throws IOException {
        service.deleteProduct(id);
        return ResponseEntity.noContent().build();
    }

    @GetMapping("/search")
    public ResponseEntity<SearchResult> search(
            @RequestParam(required = false) String q,
            @RequestParam(required = false) String brand,
            @RequestParam(required = false) String category,
            @RequestParam(required = false) String inStock,
            @RequestParam(required = false) String currency,
            @RequestParam(required = false) String minPrice,
            @RequestParam(required = false) String maxPrice,
            @RequestParam(defaultValue = "0") int page,
            @RequestParam(defaultValue = "20") int size,
            @RequestParam(required = false) String userId,
            @RequestParam(required = false) String sessionId
    ) throws IOException {
        Map<String, String> filters = new HashMap<>();
        if (brand != null) filters.put("brand", brand);
        if (category != null) filters.put("category", category);
        if (inStock != null) filters.put("inStock", inStock);
        if (currency != null) filters.put("currency", currency);
        if (minPrice != null) filters.put("minPrice", minPrice);
        if (maxPrice != null) filters.put("maxPrice", maxPrice);

        return ResponseEntity.ok(service.searchProducts(q, filters, page, size, userId, sessionId));
    }

    @GetMapping("/suggest")
    public ResponseEntity<List<String>> suggest(@RequestParam(required = false, defaultValue = "") String prefix,
                                                @RequestParam(defaultValue = "10") int size) throws IOException {
        return ResponseEntity.ok(service.suggestQueries(prefix, size));
    }
}

